// Pseudo-code: verify and accumulate a batch of shares securely
function processBatch(batch){
  const maskedSum = batch.shares.reduce((a,s)=>a + s.maskedValue,0);
  // server-side de-masking happens with stored keys
  return unmask(maskedSum);
}
```

## Follow-up Questions

