## Code Example
```javascript
// Enforce max delta across groups after score computation
function applyFairness(scores, groups, maxDelta) {
  const groupScores = groupByRegion(scores);
  const means = Object.fromEntries(
    Object.entries(groupScores).map(([k, v]) => [k, mean(v)])
  );
  const globalMean = mean(Object.values(means));

  Object.keys(means).forEach(group => {
    const delta = Math.abs(means[group] - globalMean);
    if (delta > maxDelta) {
      const adjustment = (globalMean - means[group]) > 0 
        ? maxDelta - delta 
        : delta - maxDelta;
      groupScores[group] = groupScores[group].map(s => s + adjustment);
    }
  });
  return flatten(groupScores);
}
```

