  const nonceKey = `nonce:${masked_user_id}:${nonce}`;
  if (await redis.exists(nonceKey)) {
    return res.status(409).json({ error: 'REPLAY_DETECTED', message: 'Nonce has been used' });
  }
  await redis.setex(nonceKey, 300, '1'); // Store for 5 minutes

  // 3. Model version validation
  const knownVersions = ['v1.0', 'v1.1', 'v2.0'];
  if (!knownVersions.includes(model_version)) {
    return res.status(400).json({ error: 'UNKNOWN_MODEL_VERSION', message: 'Model version not supported' });
  }

  // 4. Clock skew tolerance (±5 minutes)
  const now = Date.now();
  const skewTolerance = 5 * 60 * 1000;
  if (Math.abs(now - client_timestamp) > skewTolerance) {
    return res.status(400).json({ error: 'CLOCK_SKEW', message: 'Client timestamp outside acceptable range' });
  }

  // 5. Score bounds validation (0-100)
  if (typeof cca_score !== 'number' || cca_score < 0 || cca_score > 100) {
    return res.status(400).json({ error: 'INVALID_SCORE', message: 'CCA score must be a number between 0 and 100' });
  }

  // 6. Cross-check with cached score (if available)
  const cachedScore = await redis.get(`cca_score:${masked_user_id}`);
  if (cachedScore !== null && Math.abs(cachedScore - cca_score) > 10) {
    return res.status(409).json({ error: 'SCORE_MISMATCH', message: 'Score significantly differs from cached value' });
  }

  // 7. Signature verification
  const payload = `${masked_user_id}:${model_version}:${client_timestamp}:${cca_score}:${nonce}`;
  const isValid = await verifySignature(signature, payload, masked_user_id);
  if (!isValid) {
    return res.status(401).json({ error: 'INVALID_SIGNATURE', message: 'Signature verification failed' });
  }

  // Success
  await redis.set(`cca_score:${masked_user_id}`, cca_score);
  return res.status(200).json({ status: 'valid', cca_score });
});
```

