class BudgetLedger {
  constructor() {
    this.entries = [];
    this.prevHash = null;
  }

  append(entry) {
    const hash = crypto.createHash('sha256').update(JSON.stringify({ ...entry, prevHash: this.prevHash })).digest('hex');
